def inventory_total_092(events):
    inventory = {}
    for event in events:
        parts = event.split()
        if len(parts) != 3:
            continue
        action, item, raw_count = parts
        try:
            count = int(raw_count)
        except ValueError:
            continue
        if count < 0:
            continue
        if action == "add":
            inventory[item] = inventory.get(item, 0) + count
        elif action == "remove":
            inventory[item] = max(0, inventory.get(item, 0) - count)
    return sum(inventory.values())
